import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { DomSanitizer, SafeResourceUrl } from '@angular/platform-browser';
import { ModuloService } from '../../../core/services/modulo.service';
import { VideoService } from '../../../core/services/video.service';
import { ModuloResponse } from '../../../core/models/modulo.model';
import { VideoRequest, VideoResponse } from '../../../core/models/video.model';
import { ToastService } from '../../../core/services/toast.service';
import { ConfirmModalComponent } from '../../../core/components/confirm-modal/confirm-modal.component';
import { extraerIdYoutube } from '../../../core/utils/youtube.utils';

@Component({
  selector: 'app-videos',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ReactiveFormsModule,
    ConfirmModalComponent
  ],
  templateUrl: './videos.component.html',
  styleUrls: ['./videos.component.css']
})
export class VideosComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private moduloService = inject(ModuloService);
  private videoService = inject(VideoService);
  private fb = inject(FormBuilder);
  private sanitizer = inject(DomSanitizer);
  private toastService = inject(ToastService);

  moduloId!: number;
  modulo: ModuloResponse | null = null;
  videos: VideoResponse[] = [];
  filteredVideos: VideoResponse[] = [];
  searchQuery = '';
  dateSortOrder: 'desc' | 'asc' = 'desc';
  currentPage = 1;
  readonly pageSize = 10;

  // Modal controls
  showVideoModal = false;
  isEditMode = false;
  isFormSubmitting = false;
  modalErrorMsg = '';

  // Confirm modal controls
  showConfirmModal = false;
  confirmModalType: 'success' | 'danger' | 'info' | 'warning' = 'warning';
  confirmModalTitle = '';
  confirmModalMessage = '';
  pendingVideoAction: (() => void) | null = null;

  selectedVideo: VideoResponse | null = null;

  // Youtube Live Preview
  youtubeId = '';
  safeEmbedUrl: SafeResourceUrl | null = null;

  videoForm: FormGroup = this.fb.group({
    titulo: ['', [Validators.required, Validators.minLength(3), Validators.maxLength(200)]],
    descripcion: ['', [Validators.required, Validators.minLength(5)]],
    youtubeUrl: ['', [Validators.required, Validators.pattern('^(https?:\\/\\/)?(www\\.)?(youtube\\.com|youtu\\.be)\\/.+$')]],
    orden: [1, [Validators.required, Validators.min(1), Validators.max(999)]],
    estado: [true]
  });

  ngOnInit(): void {
    this.route.paramMap.subscribe(params => {
      const idParam = params.get('id');
      if (idParam) {
        this.moduloId = Number(idParam);
        this.loadModuloData();
      } else {
        this.router.navigate(['/dashboard/cursos']);
      }
    });
  }

  loadModuloData(): void {
    this.moduloService.obtenerModulo(this.moduloId).subscribe({
      next: (data) => {
        this.modulo = data;
        this.loadVideos();
      },
      error: (err) => {
        console.error('Error al obtener modulo', err);
        this.router.navigate(['/dashboard/cursos']);
      }
    });
  }

  loadVideos(): void {
    this.videoService.listarVideosPorModulo(this.moduloId).subscribe({
      next: (data) => {
        this.videos = data;
        this.applyFilter();
      },
      error: (err) => {
        console.error('Error al listar videos', err);
      }
    });
  }

  applyFilter(): void {
    const query = this.searchQuery.trim().toLowerCase();
    this.filteredVideos = this.videos.filter(v =>
      !query ||
      v.titulo.toLowerCase().includes(query) ||
      v.descripcion.toLowerCase().includes(query) ||
      v.fechaCreacion.toLowerCase().includes(query)
    ).sort((a, b) => {
      const d1 = new Date(a.fechaCreacion).getTime() || 0;
      const d2 = new Date(b.fechaCreacion).getTime() || 0;
      return this.dateSortOrder === 'asc' ? d1 - d2 : d2 - d1;
    });
    this.currentPage = 1;
  }

  get totalPages(): number {
    return Math.max(1, Math.ceil(this.filteredVideos.length / this.pageSize));
  }

  get paginatedVideos(): VideoResponse[] {
    const start = (this.currentPage - 1) * this.pageSize;
    return this.filteredVideos.slice(start, start + this.pageSize);
  }

  onDateSortChange(order: string): void {
    this.dateSortOrder = order === 'asc' ? 'asc' : 'desc';
    this.applyFilter();
  }

  goToPage(page: number): void {
    if (page < 1 || page > this.totalPages) return;
    this.currentPage = page;
  }

  openCreateModal(): void {
    this.isEditMode = false;
    this.modalErrorMsg = '';
    this.selectedVideo = null;
    this.youtubeId = '';
    this.safeEmbedUrl = null;
    this.videoForm.reset({
      titulo: '',
      descripcion: '',
      youtubeUrl: '',
      orden: this.videos.length + 1,
      estado: true
    });
    this.showVideoModal = true;
  }

  openEditModal(video: VideoResponse): void {
    this.isEditMode = true;
    this.modalErrorMsg = '';
    this.selectedVideo = video;
    
    this.videoForm.patchValue({
      titulo: video.titulo,
      descripcion: video.descripcion,
      youtubeUrl: video.youtubeUrl,
      orden: video.orden,
      estado: video.estado
    });

    this.onUrlInput();
    this.showVideoModal = true;
  }

  closeVideoModal(): void {
    this.showVideoModal = false;
    this.isFormSubmitting = false;
  }

  onUrlInput(): void {
    const url = this.videoForm.value.youtubeUrl || '';
    const id = this.extraerIdYoutube(url);
    if (id) {
      this.youtubeId = id;
      this.safeEmbedUrl = this.sanitizer.bypassSecurityTrustResourceUrl('https://www.youtube.com/embed/' + id);
    } else {
      this.youtubeId = '';
      this.safeEmbedUrl = null;
    }
  }

  toggleEstado(video: VideoResponse): void {
    const nuevoEstado = !video.estado;
    const accion = nuevoEstado ? 'Activar' : 'Desactivar';
    
    this.confirmModalType = nuevoEstado ? 'success' : 'warning';
    this.confirmModalTitle = `¿${accion} Video?`;
    this.confirmModalMessage = `¿Estás seguro de que deseas ${accion.toLowerCase()} el video "${video.titulo}"?`;
    
    this.pendingVideoAction = () => {
      this.videoService.cambiarEstado(video.id, nuevoEstado).subscribe({
        next: () => {
          video.estado = nuevoEstado;
          this.toastService.success(`Video "${video.titulo}" ${nuevoEstado ? 'activado' : 'desactivado'} con éxito.`);
          this.showConfirmModal = false;
        },
        error: (err) => {
          this.toastService.error(err.error?.message || 'Error al cambiar el estado del video.');
          this.showConfirmModal = false;
        }
      });
    };
    
    this.showConfirmModal = true;
  }

  confirmAction(): void {
    if (this.pendingVideoAction) {
      this.pendingVideoAction();
    }
  }

  onSubmit(): void {
    if (this.videoForm.invalid) {
      this.videoForm.markAllAsTouched();
      this.toastService.warning('Por favor complete todos los campos requeridos del video correctamente.');
      return;
    }

    this.isFormSubmitting = true;
    this.modalErrorMsg = '';

    const req: VideoRequest = {
      moduloId: this.moduloId,
      titulo: this.videoForm.value.titulo,
      descripcion: this.videoForm.value.descripcion,
      youtubeUrl: this.videoForm.value.youtubeUrl,
      orden: Number(this.videoForm.value.orden)
    };

    if (this.isEditMode && this.selectedVideo) {
      this.videoService.editarVideo(this.selectedVideo.id, req).subscribe({
        next: () => {
          const stateChanged = this.videoForm.value.estado !== this.selectedVideo!.estado;
          if (stateChanged) {
            this.videoService.cambiarEstado(this.selectedVideo!.id, this.videoForm.value.estado).subscribe({
              next: () => {
                this.loadVideos();
                this.toastService.success('Video y su estado actualizados con éxito.');
                this.closeVideoModal();
              },
              error: (err) => this.handleError(err)
            });
          } else {
            this.loadVideos();
            this.toastService.success('Video modificado con éxito.');
            this.closeVideoModal();
          }
        },
        error: (err) => this.handleError(err)
      });
    } else {
      this.videoService.crearVideo(req).subscribe({
        next: () => {
          this.loadVideos();
          this.toastService.success('Video creado con éxito.');
          this.closeVideoModal();
        },
        error: (err) => this.handleError(err)
      });
    }
  }

  extraerIdYoutube = extraerIdYoutube;

  private handleError(err: any): void {
    this.isFormSubmitting = false;
    this.modalErrorMsg = err.error?.message || 'Error al procesar el video.';
    this.toastService.error(this.modalErrorMsg);
  }
}
<div class="space-y-8 font-body text-slate-800 dark:text-slate-200 transition-colors duration-300" *ngIf="modulo">

  <!-- Back button -->
  <div class="flex items-center">
    <a 
      [routerLink]="['/dashboard/cursos', modulo.cursoId]" 
      class="flex items-center gap-1.5 text-xs font-bold text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-100 uppercase tracking-widest transition-colors">
      <span class="material-symbols-outlined text-sm">arrow_back</span>
      <span>Volver a Módulos del Curso</span>
    </a>
  </div>

  <!-- Header Banner: Structured Course and Module context -->
  <div class="border border-slate-200 dark:border-slate-800 p-8 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] flex flex-col md:flex-row justify-between items-start md:items-center gap-6 transition-colors duration-300">
    <div>
      <div class="flex items-center gap-2">
        <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 px-2 py-0.5 uppercase tracking-widest rounded-none">
          Curso: {{ modulo.cursoNombre }}
        </span>
      </div>
      <h1 class="text-2xl font-black text-slate-900 dark:text-slate-100 mt-2 tracking-tight uppercase leading-none">
        Módulo {{ modulo.orden }}: {{ modulo.nombre }}
      </h1>
      <p class="text-slate-500 dark:text-slate-400 text-xs mt-1">Gestión y secuenciación de los videos de aprendizaje interactivo.</p>
    </div>
    <button 
      (click)="openCreateModal()" 
      class="flex items-center gap-2 px-4 py-2.5 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none">
      <span class="material-symbols-outlined text-sm">add</span>
      <span>Agregar Video</span>
    </button>
  </div>

  <!-- Videos Workspace -->
  <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] overflow-hidden transition-colors duration-300">
    <!-- Filter bar -->
    <div class="p-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/60 flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
      <div class="relative w-full max-w-xs">
        <span class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 dark:text-slate-500">
          <span class="material-symbols-outlined text-base">search</span>
        </span>
        <input 
          [(ngModel)]="searchQuery"
          (input)="applyFilter()"
          class="block w-full pl-9 pr-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary text-xs rounded-none" 
          placeholder="Buscar video por título...">
      </div>
      <div class="flex items-center gap-2 flex-wrap">
        <select [(ngModel)]="dateSortOrder" (change)="onDateSortChange($any($event.target).value)" class="px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-xs font-bold uppercase tracking-wider">
          <option value="desc">Fecha desc</option>
          <option value="asc">Fecha asc</option>
        </select>
        <span class="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">
          {{ filteredVideos.length }} videos en el módulo
        </span>
      </div>
    </div>

    <!-- Videos List Table -->
    <div class="overflow-x-auto">
      <table class="w-full text-left border-collapse text-xs">
        <thead>
          <tr class="border-b border-slate-200 dark:border-slate-800 bg-slate-100/60 dark:bg-slate-800/70 text-slate-700 dark:text-slate-300 font-bold uppercase tracking-wider text-[10px]">
            <th class="p-4 w-20">Orden</th>
            <th class="p-4">Título del Video</th>
            <th class="p-4 w-44">Enlace YouTube</th>
            <th class="p-4 w-32">Estado</th>
            <th class="p-4 text-right w-36">Acciones</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100 dark:divide-slate-800">
          <!-- Empty state -->
          <tr *ngIf="filteredVideos.length === 0">
            <td colspan="5" class="p-12 text-center text-slate-400 dark:text-slate-500">
              <span class="material-symbols-outlined text-4xl mb-2 text-slate-300 dark:text-slate-600">smart_display</span>
              <p class="font-medium text-xs">Este módulo todavía no contiene videos registrados.</p>
            </td>
          </tr>
          <!-- Rows -->
          <tr *ngFor="let video of paginatedVideos" class="hover:bg-slate-50 dark:hover:bg-slate-800/40 transition-colors">
            <!-- Orden -->
            <td class="p-4 font-black text-slate-900 dark:text-slate-100 text-center">
              <span class="inline-block w-6 py-0.5 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-center font-mono">
                {{ video.orden }}
              </span>
            </td>
            <!-- Título -->
            <td class="p-4 font-bold text-slate-900 dark:text-slate-100">
              {{ video.titulo }}
              <span class="block font-normal text-[10px] text-slate-500 dark:text-slate-400 mt-0.5 truncate max-w-md">{{ video.descripcion }}</span>
            </td>
            <!-- YouTube URL -->
            <td class="p-4 font-mono text-[10px] text-slate-400 dark:text-slate-500 truncate max-w-xs">
              <a [href]="video.youtubeUrl" target="_blank" class="text-primary hover:underline flex items-center gap-1">
                <span class="material-symbols-outlined text-xs">link</span>
                Ver en YouTube
              </a>
            </td>
            <!-- Estado -->
            <td class="p-4">
            <span [ngClass]="video.estado ? 'bg-emerald-50 dark:bg-emerald-950/30 text-emerald-700 dark:text-emerald-200 border-emerald-200 dark:border-emerald-900/40' : 'bg-red-50 dark:bg-red-950/30 text-red-700 dark:text-red-200 border-red-200 dark:border-red-900/40'" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider border rounded-none">
                {{ video.estado ? 'ACTIVO' : 'INACTIVO' }}
              </span>
            </td>
            <!-- Acciones -->
            <td class="p-4 text-right">
              <div class="inline-flex gap-2">
                <button 
                  (click)="openEditModal(video)" 
                  title="Editar Video"
                  class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">edit</span>
                </button>
                <button 
                  (click)="toggleEstado(video)" 
                  [title]="video.estado ? 'Desactivar' : 'Activar'"
                  [ngClass]="video.estado ? 'border-red-200 text-red-600 hover:bg-red-50' : 'border-emerald-200 text-emerald-600 hover:bg-emerald-50'"
                  class="p-1.5 border rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">
                    {{ video.estado ? 'block' : 'check_circle' }}
                  </span>
                </button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
    <div *ngIf="filteredVideos.length > pageSize" class="p-4 border-t border-slate-200 dark:border-slate-800 flex items-center justify-between">
      <button (click)="goToPage(currentPage - 1)" [disabled]="currentPage===1" class="px-3 py-2 border text-[10px] font-bold uppercase">Anterior</button>
      <div class="text-[10px] font-bold uppercase">Página {{ currentPage }} de {{ totalPages }}</div>
      <button (click)="goToPage(currentPage + 1)" [disabled]="currentPage===totalPages" class="px-3 py-2 border text-[10px] font-bold uppercase">Siguiente</button>
    </div>
  </div>

  <!-- Create/Edit Video Modal -->
  <div *ngIf="showVideoModal" role="dialog" aria-modal="true" class="fixed inset-0 bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4" (click)="closeVideoModal()">
    <div class="w-full max-w-3xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-2xl rounded-none overflow-hidden flex flex-col md:flex-row relative transition-colors duration-300" (click)="$event.stopPropagation()">

      <!-- Left Column: Form Inputs -->
      <div class="w-full md:w-3/5 p-6 border-r border-slate-200 dark:border-slate-800 flex flex-col justify-between">
        <div>
          <!-- Header -->
          <div class="border-b border-slate-200 dark:border-slate-800 pb-3 mb-4 flex items-center justify-between">
            <h3 class="text-sm font-black text-slate-900 dark:text-slate-100 uppercase tracking-wider">
              {{ isEditMode ? 'Editar Video' : 'Agregar Video al Módulo' }}
            </h3>
            <button (click)="closeVideoModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-200 md:hidden">
              <span class="material-symbols-outlined text-lg">close</span>
            </button>
          </div>

          <!-- Form Body -->
          <form [formGroup]="videoForm" class="space-y-4">
            <div *ngIf="modalErrorMsg" class="flex items-start gap-2 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900/40 text-red-800 dark:text-red-200 p-3 rounded-none text-[11px] font-semibold">
              <span class="material-symbols-outlined text-red-600 text-base">warning</span>
              <span>{{ modalErrorMsg }}</span>
            </div>

            <!-- Titulo -->
            <div>
              <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Título del Video *</label>
              <input 
                formControlName="titulo" 
                type="text" 
                class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
                placeholder="Ej. Introducción al entorno de trabajo">
              <p *ngIf="videoForm.get('titulo')?.hasError('required') && videoForm.get('titulo')?.touched" class="text-[10px] text-red-600 mt-1">El título es obligatorio.</p>
              <p *ngIf="videoForm.get('titulo')?.hasError('minlength') && videoForm.get('titulo')?.touched" class="text-[10px] text-red-600 mt-1">Debe tener al menos 3 caracteres.</p>
            </div>

            <!-- Descripcion -->
            <div>
              <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Descripción *</label>
              <textarea 
                formControlName="descripcion" 
                rows="2" 
                class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
                placeholder="Indica un resumen del video..."></textarea>
              <p *ngIf="videoForm.get('descripcion')?.hasError('required') && videoForm.get('descripcion')?.touched" class="text-[10px] text-red-600 mt-1">La descripción es obligatoria.</p>
              <p *ngIf="videoForm.get('descripcion')?.hasError('minlength') && videoForm.get('descripcion')?.touched" class="text-[10px] text-red-600 mt-1">Debe tener al menos 5 caracteres.</p>
            </div>

            <!-- Youtube URL -->
            <div>
              <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">URL de YouTube *</label>
              <input 
                formControlName="youtubeUrl" 
                type="text" 
                (input)="onUrlInput()"
                class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
                placeholder="Ej. https://www.youtube.com/watch?v=dQw4w9WgXcQ">
              <p *ngIf="videoForm.get('youtubeUrl')?.hasError('required') && videoForm.get('youtubeUrl')?.touched" class="text-[10px] text-red-600 mt-1">Ingrese un enlace de YouTube obligatorio.</p>
              <p *ngIf="videoForm.get('youtubeUrl')?.hasError('pattern') && videoForm.get('youtubeUrl')?.touched" class="text-[10px] text-red-600 mt-1">Ingrese un enlace de YouTube válido.</p>
            </div>

            <div class="grid grid-cols-2 gap-4">
              <!-- Orden -->
              <div>
                <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Orden de Reproducción *</label>
                <input 
                  formControlName="orden" 
                  type="number" 
                  class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
                <p *ngIf="videoForm.get('orden')?.hasError('required') && videoForm.get('orden')?.touched" class="text-[10px] text-red-600 mt-1">El orden es requerido.</p>
                <p *ngIf="videoForm.get('orden')?.hasError('min') && videoForm.get('orden')?.touched" class="text-[10px] text-red-600 mt-1">El orden mínimo es 1.</p>
                <p *ngIf="videoForm.get('orden')?.hasError('max') && videoForm.get('orden')?.touched" class="text-[10px] text-red-600 mt-1">El orden máximo es 999.</p>
              </div>
              <!-- Estado -->
              <div>
                <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Estado</label>
                <select 
                  formControlName="estado" 
                  class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
                  <option [ngValue]="true">ACTIVO</option>
                  <option [ngValue]="false">INACTIVO</option>
                </select>
              </div>
            </div>
          </form>
        </div>

        <!-- Buttons -->
        <div class="pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-end gap-3 mt-6">
          <button 
            type="button" 
            (click)="closeVideoModal()" 
            class="px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors rounded-none">
            Cancelar
          </button>
          <button 
            type="button" 
            (click)="onSubmit()"
            [disabled]="videoForm.invalid || isFormSubmitting" 
            class="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none disabled:opacity-55">
            {{ isFormSubmitting ? 'Guardando...' : 'Guardar Video' }}
          </button>
        </div>
      </div>

      <!-- Right Column: Live YouTube Player / Thumbnail Preview -->
      <div class="w-full md:w-2/5 bg-slate-50 dark:bg-slate-950/40 p-6 flex flex-col justify-between select-none">
        <div class="hidden md:flex justify-between items-center border-b border-slate-200 dark:border-slate-800 pb-3 mb-4 w-full">
          <span class="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Vista Previa de Video</span>
          <button (click)="closeVideoModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-200">
            <span class="material-symbols-outlined text-lg">close</span>
          </button>
        </div>

        <!-- Live Preview Content -->
        <div class="flex-grow flex flex-col justify-center items-center h-full">

          <!-- Case 1: Video ID detected -> Embed Player & Info -->
          <div *ngIf="youtubeId" class="w-full space-y-4">

            <!-- Safe iFrame Player Container -->
            <div class="aspect-video w-full border border-slate-300 dark:border-slate-700 bg-slate-900 relative">
              <iframe 
                *ngIf="safeEmbedUrl" 
                [src]="safeEmbedUrl" 
                class="absolute inset-0 w-full h-full"
                frameborder="0" 
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                allowfullscreen>
              </iframe>
            </div>

            <!-- Thumbnail view helper -->
            <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-3 space-y-1.5">
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase">Miniatura (YouTube API HQ)</span>
              <div class="aspect-video w-full overflow-hidden border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-900">
                <img 
                  [src]="'https://img.youtube.com/vi/' + youtubeId + '/mqdefault.jpg'" 
                  alt="Previsualización de YouTube" 
                  class="w-full h-full object-cover">
              </div>
              <span class="block text-[9px] font-mono text-slate-400 dark:text-slate-500 mt-1 truncate">ID detectado: {{ youtubeId }}</span>
            </div>

          </div>

          <!-- Case 2: No video ID detected -> Empty Placeholder State -->
          <div *ngIf="!youtubeId" class="text-center p-8 border border-dashed border-slate-300 dark:border-slate-700 w-full aspect-video flex flex-col justify-center items-center bg-slate-100/50 dark:bg-slate-900/40">
            <span class="material-symbols-outlined text-4xl text-slate-300 dark:text-slate-600 animate-pulse">play_circle</span>
            <h4 class="text-xs font-bold text-slate-700 dark:text-slate-200 uppercase mt-2">Pegue un enlace</h4>
            <p class="text-[10px] text-slate-400 dark:text-slate-500 mt-1 leading-normal max-w-xs">Ingrese una URL válida de YouTube para generar la vista previa e integrar el player embebido.</p>
          </div>

        </div>

        <div></div> <!-- Spacing helper -->

      </div>

  </div>

  <!-- Confirm modal -->
  <app-confirm-modal
    [visible]="showConfirmModal"
    [type]="confirmModalType"
    [title]="confirmModalTitle"
    [message]="confirmModalMessage"
    confirmText="Confirmar"
    (onConfirm)="confirmAction()"
    (onCancel)="showConfirmModal = false">
  </app-confirm-modal>

</div>
